export const DEFAULT_ENGINE = 'dot';
export const DEFAULT_FORMAT = 'svg';
export const KNOWN_ENGINES = [
    'dot',
    'neato',
    'fdp',
    'sfdp',
    'circo',
    'twopi',
    'osage',
    'patchwork',
];
export const KNOWN_TEXT_FORMATS = [
    'svg',
    'json',
    'dot',
    'xdot',
    'plain',
];
export class GraphvizWebError extends Error {
    constructor(code, message, options = {}) {
        super(message);
        this.name = 'GraphvizWebError';
        this.code = code;
        this.issues = options.issues ?? [];
        if (options.cause !== undefined) {
            this.cause = options.cause;
        }
    }
}
export async function loadDefaultVizWasmModule() {
    // Import the compiled Wasm module from output/wasm/viz.js
    // This module is generated by emscripten with MODULARIZE=1
    const vizModuleFactory = await import('output/wasm/viz.js');
    const VizModuleFactory = vizModuleFactory.default;
    // Create a wrapper that conforms to the VizWasmModule interface
    // The factory returns a Promise that resolves to the Emscripten instance
    return {
        instance: async () => {
            const emscriptenInstance = await VizModuleFactory();
            return wrapEmscriptenInstance(emscriptenInstance);
        },
    };
}
// Wrapper function to adapt Emscripten instance to VizWasmInstance interface
function wrapEmscriptenInstance(emInstance) {
    return {
        get graphvizVersion() {
            const getVersion = emInstance.cwrap('gv_version', 'string', []);
            return getVersion();
        },
        get engines() {
            const getEngines = emInstance.cwrap('gv_get_engines', 'string', []);
            return JSON.parse(getEngines());
        },
        get formats() {
            const getFormats = emInstance.cwrap('gv_get_formats', 'string', []);
            return JSON.parse(getFormats());
        },
        render(input, options) {
            const render = emInstance.cwrap('gv_render', 'string', ['string', 'string']);
            try {
                const optionsJson = JSON.stringify(options || {});
                const resultJson = render(input, optionsJson);
                return JSON.parse(resultJson);
            }
            catch (error) {
                return {
                    status: 'failure',
                    errors: [
                        {
                            level: 'error',
                            message: error instanceof Error ? error.message : String(error),
                        },
                    ],
                };
            }
        },
        renderFormats(input, formats, options) {
            const renderFormats = emInstance.cwrap('gv_render_formats', 'string', ['string', 'string', 'string']);
            try {
                const formatsJson = JSON.stringify(formats);
                const optionsJson = JSON.stringify(options || {});
                const resultJson = renderFormats(input, formatsJson, optionsJson);
                return JSON.parse(resultJson);
            }
            catch (error) {
                return {
                    status: 'failure',
                    errors: [
                        {
                            level: 'error',
                            message: error instanceof Error ? error.message : String(error),
                        },
                    ],
                };
            }
        },
    };
}
export function normalizeRenderOptions(options = {}) {
    return {
        ...options,
        engine: options.engine ?? DEFAULT_ENGINE,
        format: options.format ?? DEFAULT_FORMAT,
    };
}
export function snapshotCapabilities(viz) {
    return {
        graphvizVersion: viz.graphvizVersion,
        engines: [...viz.engines],
        formats: [...viz.formats],
    };
}
export function issuesToMessage(issues, fallback) {
    const messages = issues
        .map((issue) => issue.message.trim())
        .filter((message) => message.length > 0);
    return messages.length > 0 ? messages.join('; ') : fallback;
}
export function assertEngineSupported(viz, engine) {
    if (engine && !viz.engines.includes(engine)) {
        throw new GraphvizWebError('UNSUPPORTED_ENGINE', `Engine "${engine}" is not available in this Wasm build. Supported engines: ${viz.engines.join(', ')}.`);
    }
}
export function assertFormatSupported(viz, format) {
    if (format && !viz.formats.includes(format)) {
        throw new GraphvizWebError('UNSUPPORTED_FORMAT', `Format "${format}" is not available in this Wasm build. Supported formats: ${viz.formats.join(', ')}.`);
    }
}
export function assertFormatsSupported(viz, formats) {
    const unsupported = formats.filter((format) => !viz.formats.includes(format));
    if (unsupported.length > 0) {
        throw new GraphvizWebError('UNSUPPORTED_FORMAT', `Formats "${unsupported.join(', ')}" are not available in this Wasm build. Supported formats: ${viz.formats.join(', ')}.`);
    }
}
export function assertActive(disposed, surface) {
    if (disposed) {
        throw new GraphvizWebError('DISPOSED', `${surface} has already been disposed.`);
    }
}
